/* ==========================================================
   名称：神秘紫色魔法主题 v9.0 (macOS布局)
   样式作者：AI Generated
   版本：v9.0
   基于：复古MacOS UI主题 @Junezz
   ========================================================== */

/* 字体 */
@import url("https://fontsapi.zeoseven.com/570/main/result.css");

body {
    font-family: "Fusion Pixel 12px Monospaced zh_hans";
    font-weight: normal;
    background: linear-gradient(180deg, #551a80 0%, #3a1265 10%, #250a4a 22%, #180632 38%, #0d0320 55%, #070212 75%, #04010a 100%);
    min-height: 100vh;
    position: relative;
    overflow-x: hidden;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: 
        radial-gradient(circle at 10% 6%, rgba(250, 220, 255, 0.25) 0%, transparent 55%),
        radial-gradient(circle at 90% 94%, rgba(255, 240, 155, 0.2) 0%, transparent 55%),
        radial-gradient(circle at 46% 46%, rgba(230, 195, 252, 0.14) 0%, transparent 75%),
        radial-gradient(circle at 20% 80%, rgba(252, 220, 255, 0.16) 0%, transparent 65%),
        radial-gradient(circle at 80% 20%, rgba(235, 200, 252, 0.12) 0%, transparent 60%);
    pointer-events: none;
    z-index: -1;
}

body::after {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-image: 
        radial-gradient(3px 3px at 30px 40px, rgba(255, 255, 255, 0.9), transparent),
        radial-gradient(2px 2px at 65px 95px, rgba(255, 255, 255, 0.7), transparent),
        radial-gradient(1.5px 1.5px at 115px 55px, rgba(255, 255, 255, 0.95), transparent),
        radial-gradient(2.5px 2.5px at 185px 145px, rgba(255, 255, 255, 0.8), transparent),
        radial-gradient(1.5px 1.5px at 255px 105px, rgba(255, 255, 255, 0.92), transparent),
        radial-gradient(2px 2px at 325px 175px, rgba(255, 255, 255, 0.6), transparent),
        radial-gradient(1.5px 1.5px at 385px 85px, rgba(255, 255, 255, 0.85), transparent),
        radial-gradient(2.5px 2.5px at 455px 205px, rgba(255, 255, 255, 0.75), transparent),
        radial-gradient(1.5px 1.5px at 535px 115px, rgba(255, 255, 255, 0.9), transparent),
        radial-gradient(2px 2px at 615px 165px, rgba(255, 255, 255, 0.65), transparent),
        radial-gradient(3px 3px at 165px 235px, rgba(255, 240, 155, 0.75), transparent),
        radial-gradient(2px 2px at 415px 295px, rgba(255, 240, 155, 0.55), transparent),
        radial-gradient(1.5px 1.5px at 295px 365px, rgba(255, 240, 155, 0.65), transparent),
        radial-gradient(2px 2px at 100px 300px, rgba(210, 180, 255, 0.6), transparent),
        radial-gradient(1.5px 1.5px at 500px 320px, rgba(210, 180, 255, 0.5), transparent);
    background-size: 680px 340px;
    pointer-events: none;
    z-index: -1;
}

code, textarea, #send_textarea, input, select, button, .text_pole, .font-family-reset {
  font-family: inherit;
}

  :root {
    --mainFontSize: calc(var(--fontScale)* 16px); /* 主字体大小 */
    --avatar-base-width: 48px; /* 头像宽度 */
    --avatar-base-height: 48px; /* 头像高度 */
    --topbarIconSize: calc(var(--mainFontSize)* 1.3); /* 顶栏图标大小 */
    --genericRadius: 0px; /* 通用圆角 */
    --warning: #ff9a9a;
    --crimson70a: rgba(255, 235, 255, 0.8);
    --crimson-hover: color-mix(in srgb, var(--SmartThemeUnderlineColor), transparent 90%) !important;
    --standardIconSize: calc(var(--mainFontSize)* 1);
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
    --bottomFormBlockPadding: calc(var(--mainFontSize) / 1.5);
    --scrollBarWidth: 3px;
    --pagePadding: calc(var(--scrollBarWidth) + 9px);
    --genericLineHeight: calc(var(--mainFontSize)* 1.9); /* 通用行高 */

    /* ==== 所有颜色定义 - 保持紫色魔法配色 ==== */
    --utilityColor: var(--black50a); /* 说明文字 */
    --navBackgroundColor: var(--SmartThemeBlurTintColor); /* 顶栏和底栏背景颜色 */
    --buttonFill: rgba(255, 240, 155, 0.2); /* 按钮背景颜色 */
    --menuBackgroundColor: var(--navBackgroundColor); /* 菜单背景颜色 */
    --accentColor: var(--SmartThemeUnderlineColor); /* 装饰色1 思维链，文字装饰，段落装饰等 */
    --accentColorOverlay: color-mix(in srgb, var(--SmartThemeBorderColor), transparent 95%); /* 装饰色2半透明 消息里头像和名字的背景颜色 */
    --scrollBarColor: var(--SmartThemeUnderlineColor); /* 滚动条颜色 */
    --boxShadowSubtle: 2px 2px 0px var(--SmartThemeBorderColor); /* 阴影颜色 */
    --boxShadowSubtleAlt: 2px 2px 0px var(--SmartThemeBorderColor); /* 阴影颜色 */
    --goldBorder: linear-gradient(135deg, #ffd700, #ffed4a, #ffd700, #e6c800, #d4a437, #ffd700);
    --purpleGlow: rgba(200, 160, 255, 0.6);
    --magicPurple: #9b59b6;
    --deepPurple: #4a1d7a;
    --starGold: #ffd700;
  }

  /* ==== 样式重置与基础样式 ==== */
  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  /* ==== 消息样式 ==== */
  .mes_chat {
    padding: var(--pagePadding) !important;
  }

  .mes {
    padding: var(--pagePadding) 0 !important;
    position: relative;
  }

  .mes .grouped {
    width: 100% !important;
  }

  .mes .mes_avatar {
    display: flex !important;
    justify-content: center;
    align-items: center;
    padding: 0 0 0 var(--pagePadding);
  }

  .mes .mes_avatar_inside {
    width: var(--avatar-base-width) !important;
    height: var(--avatar-base-height) !important;
    margin: 0 !important;
    padding: 0 !important;
    position: relative;
    z-index: 10;
  }

  .mes .mes_avatar_inside_img {
    width: var(--avatar-base-width) !important;
    height: var(--avatar-base-height) !important;
  }

  .mes .mes_name {
    position: absolute;
    top: -3px;
    left: calc(var(--pagePadding) + var(--avatar-base-width) + var(--pagePadding));
    color: var(--SmartThemeMainColor) !important;
    font-size: 0.9em;
    opacity: 0.9;
    font-weight: bold;
    letter-spacing: 0.05em;
    background: var(--accentColorOverlay);
    padding: 0.2em 0.6em;
    border-radius: var(--genericRadius);
  }

  .mes .mes_content {
    color: var(--SmartThemeMainColor) !important;
    padding: 0 var(--pagePadding) !important;
    position: relative;
  }

  /* ==== 消息气泡样式 - 直角风格 ==== */
  .mes .mes_text {
    padding: 1em 1.5em;
    background: var(--accentColorOverlay);
    position: relative;
    font-size: 1em;
    line-height: var(--genericLineHeight);
    display: inline-block;
    width: 100%;
  }

  .mes .mes_text::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(255, 230, 140, 0.5), transparent);
  }

  .mes .mes_text::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(255, 230, 140, 0.3), transparent);
  }

  /* 用户消息 */
  .mes.user_mes .mes_text {
    background: rgba(70, 40, 120, 0.4) !important;
    border: 1px solid rgba(220, 190, 255, 0.3) !important;
    border-radius: var(--genericRadius);
  }

  /* 机器人消息 */
  .mes.bot_mes .mes_text {
    background: rgba(80, 45, 135, 0.4) !important;
    border: 1px solid rgba(255, 230, 140, 0.3) !important;
    border-radius: var(--genericRadius);
  }

  /* ==== 输入框区域 ==== */
  #send_btn {
    height: 100% !important;
    border-radius: var(--genericRadius) !important;
  }

  #send_textarea {
    background: rgba(8, 3, 20, 0.98) !important;
    border: 1px solid rgba(220, 190, 255, 0.3) !important;
    color: rgba(255, 240, 155, 1) !important;
    border-radius: var(--genericRadius) !important;
    outline: none !important;
    font-family: inherit !important;
  }

  /* ==== 底部栏 ==== */
  #bottom_form {
    padding: var(--pagePadding) !important;
  }

  /* ==== 滚动条样式 ==== */
  ::-webkit-scrollbar {
    width: var(--scrollBarWidth);
    height: var(--scrollBarWidth);
  }

  ::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, #ffd700 0%, #9b59b6 50%, #4a1d7a 100%);
    border-radius: calc(var(--scrollBarWidth) / 2);
  }

  ::-webkit-scrollbar-track {
    background: rgba(12, 5, 35, 0.7);
  }

  /* ==== 各种圆角覆盖 ==== */
  .mes_image, .swipe_reply {
    border-radius: var(--genericRadius) !important;
  }

  .form-control, .swipe-container, .mes_controls {
    border-radius: var(--genericRadius) !important;
  }

  .renew {
    border-radius: 50% !important;
  }

  /* ==== 文本样式 - 保持魔法氛围 ==== */
  strong {
    color: var(--SmartThemeMainColor);
    text-shadow: 0 0 10px rgba(255, 230, 140, 0.5);
  }

  em {
    color: var(--SmartThemeItalicsColor);
  }

  blockquote {
    border-left: 3px solid var(--SmartThemeQuoteColor);
    background: rgba(50, 20, 90, 0.35);
    padding: 1em 1.5em;
    margin: 1em 0;
    color: var(--SmartThemeQuoteColor);
  }

  hr {
    border: none;
    height: 2px;
    background: linear-gradient(90deg, transparent, var(--SmartThemeUnderlineColor), transparent);
    margin: 1.4em 0;
  }

  pre, code {
    background: rgba(22, 8, 50, 0.75) !important;
    border: 1px solid rgba(220, 190, 255, 0.3) !important;
    border-radius: var(--genericRadius) !important;
    color: rgba(252, 230, 255, 0.95) !important;
  }

  ul, ol {
    list-style: none;
    padding-left: 0;
  }

  ul li::before {
    content: '✧';
    margin-right: 12px;
    color: #ffd700;
    text-shadow: 0 0 10px rgba(255, 230, 140, 0.8);
  }

  ol li::before {
    content: counter(list-counter) '.';
    margin-right: 10px;
    color: #ffd700;
    font-weight: bold;
  }

  ol {
    counter-reset: list-counter;
  }

  ol li {
    counter-increment: list-counter;
  }

  a {
    color: #ffd700;
    text-decoration: none;
    position: relative;
  }

  a::after {
    content: '';
    position: absolute;
    bottom: -2px;
    left: 0;
    width: 0;
    height: 2px;
    background: linear-gradient(90deg, #ffd700, #9b59b6);
    transition: width 0.3s ease;
  }

  a:hover::after {
    width: 100%;
  }

  /* ==== 选择文本样式 ==== */
  ::selection {
    background: rgba(155, 89, 182, 0.5);
    color: #ffeaaa;
  }

  ::-moz-selection {
    background: rgba(155, 89, 182, 0.5);
    color: #ffeaaa;
  }
